content.text:
 1	.VirtualMachinesOverviewTabUtilization--main {
 2	  .title {
 3	    display: flex;
 4	    align-items: center;
 5	    justify-content: space-between;
 6	  }
 7	  .util {
 8	    display: flex;
 9	    flex-direction: column;
10	    height: 100%;
11	    .util-upper {
12	      padding-left: var(--pf-t--global--spacer--2xl);
13	      .util-title {
14	        font-weight: var(--pf-t--global--FontWeight--semi-bold);
15	        height: var(--pf-t--global--spacer--2xl);
16	        &__subtitle {
17	          font-size: var(--pf-t--global--font--size--md);
18	        }
19	      }
20	      .util-summary {
21	        width: 100%;
22	        height: var(--pf-t--global--spacer--2xl);
23	        display: flex;
24	        align-items: flex-end;
25	        .util-summary-value {
26	          width: 50%;
27	          font-weight: var(--pf-t--global--FontWeight--normal);
28	          font-size: var(--pf-t--global--font--size--xl);
29	          line-height: normal;
30	        }
31	        .util-summary-text {
32	          width: 50%;
33	        }
34	      }
35	    }
36	    .util-chart {
37	      max-height: 8vw;
38	      .pf-v5-c-chart {
39	        height: auto;
40	      }
41	    }
42	    &.network {
43	      display: flex;
44	      flex-direction: column;
45	      height: 100%;
46	    }
47	    .network-metrics {
48	      padding-left: var(--pf-t--global--spacer--2xl);
49	      display: flex;
50	      flex-direction: column;
51	      flex-grow: 1;
52	      justify-content: center;
53	      .network-metrics--row {
54	        display: flex;
55	        &__sum,
56	        &__title {
57	          width: 50%;
58	        }
59	        &__title {
60	          margin-left: var(--pf-t--global--spacer--sm);
61	        }
62	        &__sum {
63	          font-weight: var(--pf-t--global--FontWeight--semi-bold);
64	        }
65	      }
66	    }
67	  }
68	  .util-threshold-chart {
69	    width: 100%;
70	    height: 100px;
71	  }
72	  .duration-select {
73	    display: flex;
74	    .pf-v5-c-select {
75	      flex-basis: content;
76	    }
77	  }
78	  .pf-v6-c-description-list__text.pf-m-help-text {
79	    text-underline-offset: 0.25rem;
80	  }
81	}

